-- ============================================
-- Legislacao Bloco 2 misto: Daniel Vilela / Camara Dados Abertos / projetos_lei
-- Promocao completa escopada: autoria principal em tipos verificados
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos v2
--   https://dadosabertos.camara.leg.br/api/v2/deputados/144523
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes?idDeputadoAutor=144523&ordem=DESC&ordenarPor=id&itens=100&pagina=1..5
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = daniel-vilela-camara-completo-autoria-principal-tipos-verificados-2015-2018-cutoff-20260509
--   coverage_scope = inventario_completo_camara_autoria_principal_tipos_verificados_2015_2018_cutoff_20260509
--
-- Escopo: 169 proposicoes de autoria principal (ordemAssinatura=1)
-- na Camara, em tipos verificados e anos oficiais positivos, com cutoff em 2026-05-09.
-- 282 rows oficiais ficam formalmente fora do coverage por
-- nao-autoria principal ou ano oficial nao verificavel.
--
-- Esta migration escreve somente em projetos_lei.
-- Esta migration NAO escreve em legislacao_mandato_executivo; valida baseline
-- read-only de 11 rows LME GO que permanecem ampliado_parcial em superficie separada.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  lme_count int;
  lme_target_count int;
  target_divergent_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'daniel-vilela';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'daniel-vilela: candidato ausente neste banco local/CI minimo; promocao Camara pulada';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl NOT IN (100, 249) THEN
    RAISE EXCEPTION 'Pre-condicao daniel-vilela: esperadas 100 rows antes do insert ou 249 rows idempotentes em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 11 THEN
    RAISE EXCEPTION 'Pre-condicao daniel-vilela: baseline LME GO parcial esperado 11, encontrado %', lme_count;
  END IF;

  SELECT count(*) INTO lme_target_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'daniel-vilela-camara-completo-autoria-principal-tipos-verificados-2015-2018-cutoff-20260509';
  IF lme_target_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao daniel-vilela: coverage parlamentar novo nao pode existir em LME, encontrado %', lme_target_count;
  END IF;

  SELECT count(*) INTO target_divergent_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2188620', '2183985', '2179012', '2179011', '2162601', '2158616', '2158615', '2158614', '2158613', '2158612', '2158611', '2158610', '2158609', '2158608', '2158607', '2155205', '2155204', '2155203', '2148133', '2147916', '2130405', '2128480', '2128479', '2128478', '2128476', '2127447', '2126331', '2126330', '2126329', '2126328', '2126327', '2126326', '2126325', '2126324', '2125516', '2125515', '2125514', '2125432', '2125430', '2123532', '2119972', '2116495', '2113263', '2113262', '2110404', '2110401', '2110398', '2093962', '2092690', '2091537', '2090984', '2090983', '2090981', '2089157', '2087305', '2087304', '2086210', '2086203', '2085251', '2085250', '2085249', '2085248', '2084628', '2084627', '2084626', '2084625', '2084624', '2080875', '2080874', '2078958', '2075575', '2074598', '2056815', '2056177', '2055896', '2052846', '2052844', '2041358', '2025543', '2024024', '2023906', '1786730', '1724693', '1715980', '1712375', '1712373', '1712372', '1712371', '1712370', '1712360', '1701307', '1701306', '1682913', '1672572', '1672571', '1672570', '1672434', '1672433', '1672432', '1629278', '1629277', '1629275', '1629274', '1629273', '1629272', '1629267', '1629254', '1579366', '1570577', '1570576', '1570566', '1549477', '1549225', '1549224', '1549122', '1549121', '1549120', '1549119', '1549118', '1548584', '1346022', '1306999', '1306997', '1306996', '1306995', '1306994', '1301183', '1301182', '1299562', '1299561', '1299560', '1247343', '1247342', '1247340', '1247339', '1227847', '1227846', '1227844', '1227843', '1227842', '1214820', '1214233', '1212766', '1212765', '1212764', '1203654', '1203437', '1203436', '1203435', '1203434', '1203433', '1198442', '1197936', '1049036', '1048972', '1048971', '1036770', '1028999', '996356', '996352', '996347', '996344', '996341', '988678', '988677', '988676', '988675', '961595', '961594')
    AND coverage_id IS NOT NULL
    AND coverage_id NOT IN ('daniel-vilela-camara-autoria-principal-ampliado-parcial-lote-a-20260506', 'daniel-vilela-camara-completo-autoria-principal-tipos-verificados-2015-2018-cutoff-20260509');
  IF target_divergent_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao daniel-vilela: % rows alvo tem coverage_id divergente', target_divergent_count;
  END IF;
END $$;

