    ('1549477', 'PFC', '41', 2015, 'Propõe que a Comissão de Viação e Transportes da Câmara dos Deputados fiscalize a conduta do Departamento Nacional de Trânsito - DENATRAN - em relação a atos e omissões que estariam a configurar, desde 2006, a deficiência técnica e administrativa do Departamento de Trânsito do Estado de Goiás - DETRAN/GO -, justificando a intervenção federal.', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1357037', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao Bloco 2 misto","curation_batch_id":"daniel-vilela-camara-completo-20260509","coverage_id":"daniel-vilela-camara-completo-autoria-principal-tipos-verificados-2015-2018-cutoff-20260509","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2015_2018_cutoff_20260509","previous_coverage_id":"daniel-vilela-camara-autoria-principal-ampliado-parcial-lote-a-20260506","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"camara_id_deputado":144523,"proposicao_id_api":"1549477","ordem_assinatura":1,"total_autores":1,"autor_nome":"Daniel Vilela","autor_tipo":"Deputado(a)","autoria_principal_verificada":true,"ano_oficial_verificado":true,"detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/1549477","autores_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/1549477/autores","public_url":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/1549477","fonte_oficial_verificada_em":"2026-05-10T01:16:51.768Z","coverage_status":"completo_escopado","coverage_public_status":"parlamentar_complete_mixed_with_executive_partial","coverage_cutoff":"2026-05-09","completeness_scope":"autoria principal na Camara dos Deputados em tipos verificados; LME GO permanece parcial e separado"}'::jsonb),
    ('1549225', 'PL', '2211', 2015, 'Acrescenta o § 3º ao art. 19 da Lei nº 8.112, de 11 de dezembro de 1990, que dispõe sobre o regime jurídico dos servidores públicos civis da União, das autarquias e das fundações públicas federais, para autorizar a implantação do sistema de "escritório móvel" no serviço público.', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1356340', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao Bloco 2 misto","curation_batch_id":"daniel-vilela-camara-completo-20260509","coverage_id":"daniel-vilela-camara-completo-autoria-principal-tipos-verificados-2015-2018-cutoff-20260509","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2015_2018_cutoff_20260509","previous_coverage_id":"daniel-vilela-camara-autoria-principal-ampliado-parcial-lote-a-20260506","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"camara_id_deputado":144523,"proposicao_id_api":"1549225","ordem_assinatura":1,"total_autores":1,"autor_nome":"Daniel Vilela","autor_tipo":"Deputado(a)","autoria_principal_verificada":true,"ano_oficial_verificado":true,"detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/1549225","autores_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/1549225/autores","public_url":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/1549225","fonte_oficial_verificada_em":"2026-05-10T01:16:51.768Z","coverage_status":"completo_escopado","coverage_public_status":"parlamentar_complete_mixed_with_executive_partial","coverage_cutoff":"2026-05-09","completeness_scope":"autoria principal na Camara dos Deputados em tipos verificados; LME GO permanece parcial e separado"}'::jsonb),
    ('1549224', 'PL', '2210', 2015, 'Acrescenta parágrafo ao art. 93 da Lei nº 8.213, de 24 de julho de 1991, que "dispõe sobre o Plano de Benefícios da Previdência Social e dá outras providências", para eximir de multa a empresa que comprove ter utilizado todos os meios possíveis para contratação de pessoas com deficiência, sem ter obtido êxito, por razões alheias à vontade do empregador.', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1356339', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao Bloco 2 misto","curation_batch_id":"daniel-vilela-camara-completo-20260509","coverage_id":"daniel-vilela-camara-completo-autoria-principal-tipos-verificados-2015-2018-cutoff-20260509","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2015_2018_cutoff_20260509","previous_coverage_id":"daniel-vilela-camara-autoria-principal-ampliado-parcial-lote-a-20260506","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"camara_id_deputado":144523,"proposicao_id_api":"1549224","ordem_assinatura":1,"total_autores":1,"autor_nome":"Daniel Vilela","autor_tipo":"Deputado(a)","autoria_principal_verificada":true,"ano_oficial_verificado":true,"detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/1549224","autores_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/1549224/autores","public_url":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/1549224","fonte_oficial_verificada_em":"2026-05-10T01:16:51.768Z","coverage_status":"completo_escopado","coverage_public_status":"parlamentar_complete_mixed_with_executive_partial","coverage_cutoff":"2026-05-09","completeness_scope":"autoria principal na Camara dos Deputados em tipos verificados; LME GO permanece parcial e separado"}'::jsonb),
