    ('1212764', 'PL', '1202', 2015, 'Dispõe sobre a vedação do financiamento das campanhas eleitorais por pessoas jurídicas; estabelece limites de doações para pessoas físicas; cria mecanismo de estímulo às pessoas físicas para realizações de doações eleitorais; e estipula que o doador não poderá realizar doações a candidatos de partidos diferentes, ressalvados os casos em que as doações sejam feitas a candidatos de partidos diferentes que façam parte de uma mesma coligação. Altera a Lei 9.096/95 e a Lei 9504/97.', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1322573', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao Bloco 2 misto","curation_batch_id":"daniel-vilela-camara-completo-20260509","coverage_id":"daniel-vilela-camara-completo-autoria-principal-tipos-verificados-2015-2018-cutoff-20260509","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2015_2018_cutoff_20260509","previous_coverage_id":"daniel-vilela-camara-autoria-principal-ampliado-parcial-lote-a-20260506","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"camara_id_deputado":144523,"proposicao_id_api":"1212764","ordem_assinatura":1,"total_autores":1,"autor_nome":"Daniel Vilela","autor_tipo":"Deputado(a)","autoria_principal_verificada":true,"ano_oficial_verificado":true,"detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/1212764","autores_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/1212764/autores","public_url":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/1212764","fonte_oficial_verificada_em":"2026-05-10T01:16:51.768Z","coverage_status":"completo_escopado","coverage_public_status":"parlamentar_complete_mixed_with_executive_partial","coverage_cutoff":"2026-05-09","completeness_scope":"autoria principal na Camara dos Deputados em tipos verificados; LME GO permanece parcial e separado"}'::jsonb),
